begin;

-- Importação auditável do extrato da conta Itaú Uniclass do Filipe,
-- de janeiro a junho de 2026. A solicitação do usuário confirma os lançamentos.
-- Pagamentos de cartões e transferências próprias são modelados como transferências
-- para não duplicar despesas já presentes nas faturas importadas.
do $$
begin
  if not exists (
    select 1 from public.perfis
    where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and lower(coalesce(nome, '')) like '%filipe%'
  ) then
    raise exception 'Perfil do Filipe não encontrado; importação cancelada.';
  end if;

  if exists (
    select 1 from public.contas
    where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and lower(nome) = lower('Conta Itaú Uniclass')
      and id <> 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid
  ) then
    raise exception 'Já existe outra conta chamada Conta Itaú Uniclass; importação cancelada.';
  end if;
end;
$$;

insert into public.contas (
  id, usuario_id, nome, tipo, instituicao, cor, saldo_inicial,
  data_saldo_inicial, incluir_no_patrimonio, ativa
)
values (
  'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid, 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid,
  'Conta Itaú Uniclass', 'conta_corrente', 'Itaú', '#EC7000', 6497.23,
  '2026-01-01'::date, true, true
)
on conflict (id) do update
set saldo_inicial = excluded.saldo_inicial,
    data_saldo_inicial = excluded.data_saldo_inicial,
    instituicao = excluded.instituicao,
    ativa = true;

