-- Liga ao Itaú o lado de origem da transferência de R$ 100 já importada
-- pelo extrato do Mercado Pago, evitando dois lançamentos para o mesmo Pix.
update public.movimentacoes
set conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid,
    observacoes = concat_ws(' ', observacoes,
      'Contrapartida no extrato Itaú: PIX TRANSF Filipe 05/04, lançado em 06/04/2026.'),
    metadados = metadados || $json${"contrapartida_itau":{"arquivo":"itau_extrato_012026.pdf","pagina":4,"data_lancamento":"2026-04-06","descricao_original":"PIX TRANSF Filipe 05/04"}}$json$::jsonb
where id = 'b8fdcfb2-4ace-586f-b47f-28cd0a906ca5'::uuid
  and usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
  and valor = 100.00
  and conta_destino_id = '70c10a6f-1882-5411-858a-c465dacecf29'::uuid;

