set categoria_id = '76eb021f-5f19-5d0c-9fc4-9f1a1fbf2f87'::uuid,
    conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid
where id in ('028366d0-4591-4667-9dc6-08ce9ed61148'::uuid, 'a06de776-725f-460d-88b5-45cffed0c7a8'::uuid)
  and usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid;

update public.recorrencias
set categoria_id = '520dd656-9326-5875-b2b7-a209efc414e3'::uuid,
    conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid
where id in ('09227aa5-f3e3-40f8-bd7c-6a49f9d1f3f3'::uuid, 'a0127352-6767-4b0d-b31c-8832521edb44'::uuid, 'c4a988d2-e9d0-408d-90e9-b4a39e6355eb'::uuid, '5e9f6176-8292-4c1f-bea5-32283bd212c9'::uuid)
  and usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid;

do $$
declare
  quantidade_importada integer;
  quantidade_recorrencias integer;
  saldo_reconstituido numeric(14, 2);
  saldo_2026_01 numeric(14, 2);
  saldo_2026_02 numeric(14, 2);
  saldo_2026_03 numeric(14, 2);
  saldo_2026_04 numeric(14, 2);
  saldo_2026_05 numeric(14, 2);
  saldo_2026_06 numeric(14, 2);
begin
  select count(*)
  into quantidade_importada
  from public.movimentacoes
  where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
    and metadados ->> 'importacao_lote' = 'itau-conta-filipe-2026-01-a-06';

  if quantidade_importada <> 223 then
    raise exception 'Importação Itaú incompleta: esperados 223 lançamentos, encontrados %.',
      quantidade_importada;
  end if;

  if not exists (
    select 1 from public.movimentacoes
    where id = 'b8fdcfb2-4ace-586f-b47f-28cd0a906ca5'::uuid
      and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid
      and conta_destino_id = '70c10a6f-1882-5411-858a-c465dacecf29'::uuid
  ) then
    raise exception 'A contrapartida Itaú da transferência para o Mercado Pago não foi ligada.';
  end if;

  select
    coalesce(sum(case when mes_competencia = '2026-01-01'::date then
      case
        when natureza = 'receita' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'despesa' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        when natureza = 'transferencia' and conta_destino_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'transferencia' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        else 0
      end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-02-01'::date then
      case
        when natureza = 'receita' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'despesa' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        when natureza = 'transferencia' and conta_destino_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'transferencia' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        else 0
      end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-03-01'::date then
      case
        when natureza = 'receita' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'despesa' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        when natureza = 'transferencia' and conta_destino_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'transferencia' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        else 0
      end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-04-01'::date then
      case
        when natureza = 'receita' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'despesa' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        when natureza = 'transferencia' and conta_destino_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'transferencia' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        else 0
      end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-05-01'::date then
      case
        when natureza = 'receita' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'despesa' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        when natureza = 'transferencia' and conta_destino_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'transferencia' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        else 0
      end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-06-01'::date then
      case
        when natureza = 'receita' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'despesa' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        when natureza = 'transferencia' and conta_destino_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then valor
        when natureza = 'transferencia' and conta_id = 'd64bb1b6-1140-5470-8695-7aadce45262c'::uuid then -valor
        else 0
      end else 0 end), 0)
  into saldo_2026_01, saldo_2026_02, saldo_2026_03, saldo_2026_04, saldo_2026_05, saldo_2026_06
  from public.movimentacoes
  where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
    and (
      metadados ->> 'importacao_lote' = 'itau-conta-filipe-2026-01-a-06'
      or id = 'b8fdcfb2-4ace-586f-b47f-28cd0a906ca5'::uuid
    );

  if saldo_2026_01 <> 1404.45 then
    raise exception 'Saldo líquido divergente em 2026-01: %.', saldo_2026_01;
  end if;
  if saldo_2026_02 <> 18638.49 then
    raise exception 'Saldo líquido divergente em 2026-02: %.', saldo_2026_02;
  end if;
  if saldo_2026_03 <> -8821.35 then
    raise exception 'Saldo líquido divergente em 2026-03: %.', saldo_2026_03;
  end if;
  if saldo_2026_04 <> -7797.93 then
    raise exception 'Saldo líquido divergente em 2026-04: %.', saldo_2026_04;
  end if;
  if saldo_2026_05 <> 1118.64 then
    raise exception 'Saldo líquido divergente em 2026-05: %.', saldo_2026_05;
  end if;
  if saldo_2026_06 <> -5330.78 then
    raise exception 'Saldo líquido divergente em 2026-06: %.', saldo_2026_06;
  end if;

  saldo_reconstituido := 6497.23 + -788.48;
  if saldo_reconstituido <> 5708.75 then
    raise exception 'Saldo Itaú divergente: esperado 5708.75, reconstituído %.',
      saldo_reconstituido;
  end if;

  select count(*)
  into quantidade_recorrencias
  from public.recorrencias
  where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
    and (
      (id = '6929d257-5bd0-4db4-b4f3-6371b76d476a'::uuid
       and categoria_id = '95659a0a-60c8-4a4c-88c7-30b608ef802e'::uuid
       and valor_estimado = 9455.96)
      or (id in ('028366d0-4591-4667-9dc6-08ce9ed61148'::uuid, 'a06de776-725f-460d-88b5-45cffed0c7a8'::uuid)
          and categoria_id = '76eb021f-5f19-5d0c-9fc4-9f1a1fbf2f87'::uuid)
      or (id in ('09227aa5-f3e3-40f8-bd7c-6a49f9d1f3f3'::uuid, 'a0127352-6767-4b0d-b31c-8832521edb44'::uuid, 'c4a988d2-e9d0-408d-90e9-b4a39e6355eb'::uuid, '5e9f6176-8292-4c1f-bea5-32283bd212c9'::uuid)
          and categoria_id = '520dd656-9326-5875-b2b7-a209efc414e3'::uuid)
    );

  if quantidade_recorrencias <> 7 then
    raise exception 'Nem todas as recorrências de salário, 13º e PLR foram ajustadas.';
  end if;
end;
$$;

commit;
